// Extract account_id and call_type from filename
// e.g. bens_electric_demo.m4a → { account_id: 'bens_electric', call_type: 'demo' }

const filename = items[0].json.name;
const stem = filename.replace(/\.[^/.]+$/, '');

let account_id, call_type;

if (stem.endsWith('_demo')) {
  account_id = stem.replace('_demo', '');
  call_type = 'demo';
} else if (stem.endsWith('_onboarding')) {
  account_id = stem.replace('_onboarding', '');
  call_type = 'onboarding';
} else {
  account_id = stem;
  call_type = 'demo';
}

return [{ json: { ...items[0].json, account_id, call_type, filename } }];

// Log completion of Pipeline A
const account_id = items[0].json.account_id;
const timestamp = new Date().toISOString();

return [{
  json: {
    account_id,
    pipeline: 'A',
    status: 'complete',
    v1_memo: `outputs/accounts/${account_id}/v1/account_memo.json`,
    v1_spec: `outputs/accounts/${account_id}/v1/agent_spec.json`,
    completed_at: timestamp
  }
}];

// Mock task creation — replace with Asana/Trello/Notion API call
const account_id = items[0].json.account_id;

console.log(`[TASK TRACKER] New task created:`);
console.log(`  Title: Review v1 agent spec for ${account_id}`);
console.log(`  Status: Pending onboarding`);
console.log(`  Link: outputs/accounts/${account_id}/v1/agent_spec.json`);

return items;

const fs = require('fs');
const account_id = items[0].json.account_id;
const v1_path = `outputs/accounts/${account_id}/v1/account_memo.json`;

const exists = fs.existsSync(v1_path);

if (!exists) {
  throw new Error(`v1 memo not found for ${account_id}. Run Pipeline A first.`);
}

return [{ json: { ...items[0].json, v1_memo_path: v1_path } }];

const account_id = items[0].json.account_id;
const timestamp = new Date().toISOString();

return [{
  json: {
    account_id,
    pipeline: 'B',
    status: 'complete',
    v2_memo: `outputs/accounts/${account_id}/v2/account_memo.json`,
    v2_spec: `outputs/accounts/${account_id}/v2/agent_spec.json`,
    changelog: `changelog/${account_id}_changes.json`,
    completed_at: timestamp
  }
}];

// Mock Retell notification — in production this calls Retell API
const account_id = items[0].json.account_id;

console.log(`[RETELL] Agent spec v2 ready for import:`);
console.log(`  Account: ${account_id}`);
console.log(`  Spec: outputs/accounts/${account_id}/v2/agent_spec.json`);
console.log(`  Action: Paste system_prompt into Retell UI`);
console.log(`  Note: Retell API requires paid plan — manual import required on free tier`);

return items;

const error = items[0].json.error || 'Unknown error';
const account_id = items[0].json.account_id || 'unknown';

console.error(`[ERROR] Pipeline failed for account: ${account_id}`);
console.error(`[ERROR] Reason: ${error}`);
console.error(`[ERROR] Time: ${new Date().toISOString()}`);

return [{
  json: {
    account_id,
    status: 'failed',
    error,
    failed_at: new Date().toISOString()
  }
}];
